From Summaries to Model Inference (my solution)

id_numbers &lt;- unique(DF$id_number)
obs_summaries &lt;- data.frame()
for (i in id_numbers){
  result &lt;- cbind(
    data.frame(
      id_number = i,
      pseudonym = DF$pseudonym[DF$id_number == i][1]
    ),
    all_measures(DF$response2[DF$id_number == i])
  )
  obs_summaries &lt;- rbind(
    obs_summaries, result
  )
}
